const slots = $('generate_slots').all().map(item => item.json);
const events = $input.all().map(item => item.json);

const openSlots = slots.filter(slot => {
  const slotStart = new Date(slot.start);
  const slotEnd = new Date(slot.end);

  const overlaps = events.some(event => {
    // Skip events that don't have a proper start/end dateTime (e.g. all-day events)
    if (!event.start || !event.end || !event.start.dateTime || !event.end.dateTime) {
      return false;
    }

    const eventStart = new Date(event.start.dateTime);
    const eventEnd = new Date(event.end.dateTime);
    return slotStart < eventEnd && slotEnd > eventStart;
  });

  return !overlaps;
});

return openSlots.map(slot => ({ json: slot }));

const SLOT_MINUTES = 30;
const WORK_START_HOUR = 9;
const WORK_END_HOUR = 17;

const requestedDate = $json.date;

const slots = [];
let current = new Date(`${requestedDate}T${String(WORK_START_HOUR).padStart(2,'0')}:00:00+05:00`);
const end = new Date(`${requestedDate}T${String(WORK_END_HOUR).padStart(2,'0')}:00:00+05:00`);

while (current < end) {
  const slotEnd = new Date(current.getTime() + SLOT_MINUTES * 60000);
  slots.push({
    id: slots.length,
    start: current.toISOString(),
    end: slotEnd.toISOString(),
    display: current.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', timeZone: 'Asia/Karachi' })
      + ' - ' +
      slotEnd.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', timeZone: 'Asia/Karachi' })
  });
  current = slotEnd;
}

return slots.map(slot => ({ json: slot }));
